264	static void vcpu_tb_trans(qemu_plugin_id_t id, struct qemu_plugin_tb *tb)
265	{
266	    (void) id;
267	    size_t n = qemu_plugin_tb_n_insns(tb);
268	    for (size_t i = 0; i < n; i++) {
269	        struct qemu_plugin_insn *insn = qemu_plugin_tb_get_insn(tb, i);
270	
271	        if (pc_mode) {
272	            // PC-trigger mode: vaddr-only match. qemu_plugin_insn_size lets
273	            // a future fixture park enter_pc on a compressed insn -- next-PC
274	            // is computed from the API-reported size, not assumed to be 4.
275	            if (qemu_plugin_insn_vaddr(insn) != enter_pc_arg) continue;
276	            HandoffSite *site = g_new0(HandoffSite, 1);
277	            site->kind  = HYBRID_HANDOFF_ENTER;
278	            site->vaddr = qemu_plugin_insn_vaddr(insn);
279	            site->size  = (uint32_t) qemu_plugin_insn_size(insn);
280	            qemu_plugin_register_vcpu_insn_exec_cb(
281	                insn, on_handoff, QEMU_PLUGIN_CB_R_REGS, site);
282	            continue;
283	        }
284	
285	        // CSR-trigger mode (default).
286	        size_t sz = qemu_plugin_insn_size(insn);
287	        if (sz != 4) continue;
288	        uint32_t raw = 0;
289	        if (qemu_plugin_insn_data(insn, &raw, sizeof(raw)) != sizeof(raw))
290	            continue;
291	        hybrid_handoff_kind kind = HYBRID_HANDOFF_NONE;
292	        if (!hybrid_match_handoff_insn(raw, &kind)) continue;
293	        HandoffSite *site = g_new0(HandoffSite, 1);
294	        site->kind  = kind;
295	        site->vaddr = qemu_plugin_insn_vaddr(insn);
296	        site->size  = (uint32_t) sz;
297	        qemu_plugin_register_vcpu_insn_exec_cb(
298	            insn, on_handoff, QEMU_PLUGIN_CB_R_REGS, site);
299	    }
300	}
