302	QEMU_PLUGIN_EXPORT int qemu_plugin_install(qemu_plugin_id_t id,
303	                                           const qemu_info_t *info,
304	                                           int argc, char **argv)
305	{
306	    (void) info;
307	    for (int i = 0; i < argc; i++) {
308	        g_auto(GStrv) tok = g_strsplit(argv[i], "=", 2);
309	        if (g_strcmp0(tok[0], "outfile") == 0 && tok[1]) {
310	            outfile_path = g_strdup(tok[1]);
311	        } else if (g_strcmp0(tok[0], "enter_pc") == 0 && tok[1]) {
312	            char *endp = NULL;
313	            unsigned long long v = g_ascii_strtoull(tok[1], &endp, 0);
314	            if (!endp || *endp != '\0') {
315	                fprintf(stderr, "hybrid_handoff: invalid enter_pc=%s\n",
316	                        tok[1]);
317	                return -1;
318	            }
319	            enter_pc_arg = (uint64_t) v;
320	            pc_mode = 1;
321	        } else {
322	            fprintf(stderr, "hybrid_handoff: unknown option: %s\n", argv[i]);
323	            return -1;
324	        }
325	    }
326	    if (!outfile_path) {
327	        fputs("hybrid_handoff: outfile=PATH is required\n", stderr);
328	        return -1;
329	    }
330	    if (pc_mode) {
331	        fprintf(stderr,
332	                "hybrid_handoff: PC-mode enter=0x%" PRIx64 "\n",
333	                enter_pc_arg);
334	    }
335	
336	    vcpu_state = qemu_plugin_scoreboard_new(sizeof(VcpuRegs));
337	    qemu_plugin_register_vcpu_tb_trans_cb(id, vcpu_tb_trans);
338	    return 0;
339	}
